<script setup lang="ts">import {dndFeature,expansionFeature} from '@fex/components-core'; import {createTreeController} from '@fex/components-core/tree/create-tree-controller'; import {TreeRoot,TreeViewport} from '@fex/components-vue/primitive/tree'; import Card from '@fex/components-vue/ui/card'; import DndTreeRow from './dnd-tree-row.vue'; import {departmentFieldNames,departmentTreeData,isDepartmentLeaf,type DepartmentNode} from './data'; const controller=createTreeController<DepartmentNode>({treeData:departmentTreeData,fieldNames:departmentFieldNames,isLeaf:isDepartmentLeaf,features:[expansionFeature({defaultExpandedKeys:['company','engineering','product']}),dndFeature()]})</script>
